import os
import logging
from typing import List, Dict, Any
from langchain.vectorstores import Chroma
from langchain.embeddings import HuggingFaceEmbeddings
from langchain.llms import OpenAI
from langchain.chains import RetrievalQA
from langchain.text_splitter import RecursiveCharacterTextSplitter
from langchain.docstore.document import Document
from langchain.prompts import PromptTemplate
import hashlib
import json
from pathlib import Path

# Configure logging
logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

class SecureRAGSystem:
    def __init__(self, vector_db_path: str = "chroma_db", embedding_model: str = "sentence-transformers/all-MiniLM-L6-v2"):
        self.vector_db_path = vector_db_path
        self.embedding_model = embedding_model
        self.embeddings = HuggingFaceEmbeddings(model_name=embedding_model)
        self.vector_store = None
        self.qa_chain = None
        
    def load_documents(self, documents: List[Dict[str, str]]) -> None:
        """Load documents into vector database"""
        try:
            # Validate input
            if not documents:
                raise ValueError("No documents provided")
            
            # Convert to Document objects
            docs = []
            for doc in documents:
                if not isinstance(doc, dict) or 'content' not in doc:
                    raise ValueError("Each document must be a dict with 'content' key")
                docs.append(Document(page_content=doc['content'], metadata=doc.get('metadata', {})))
            
            # Create vector store
            self.vector_store = Chroma(
                persist_directory=self.vector_db_path,
                embedding_function=self.embeddings
            )
            
            # Split documents
            text_splitter = RecursiveCharacterTextSplitter(
                chunk_size=1000,
                chunk_overlap=200,
                separators=["\n\n", "\n", " ", ""]
            )
            
            split_docs = text_splitter.split_documents(docs)
            
            # Add to vector store
            self.vector_store.add_documents(split_docs)
            self.vector_store.persist()
            
            logger.info(f"Successfully loaded {len(docs)} documents into vector store")
            
        except Exception as e:
            logger.error(f"Error loading documents: {str(e)}")
            raise
    
    def create_qa_chain(self, llm_model: str = "text-davinci-003", temperature: float = 0.3) -> None:
        """Create QA chain with secure configuration"""
        try:
            # Validate LLM model
            if not llm_model:
                raise ValueError("LLM model name cannot be empty")
            
            # Create LLM with secure parameters
            llm = OpenAI(
                model_name=llm_model,
                temperature=temperature,
                max_tokens=1500,
                top_p=1,
                frequency_penalty=0,
                presence_penalty=0,
                request_timeout=30
            )
            
            # Create prompt template
            template = """
            You are an intelligent assistant for internal company knowledge base.
            Use the following pieces of context to answer the question at the end.
            If you don't know the answer, just say that you don't know, don't try to make up an answer.
            
            Context:
            {context}
            
            Question: {question}
            Answer:
            """
            
            prompt = PromptTemplate(template=template, input_variables=["context", "question"])
            
            # Create retrieval chain
            self.qa_chain = RetrievalQA.from_chain_type(
                llm=llm,
                chain_type="stuff",
                retriever=self.vector_store.as_retriever(search_kwargs={"k": 4}),
                return_source_documents=True,
                chain_type_kwargs={"prompt": prompt}
            )
            
            logger.info("QA chain created successfully")
            
        except Exception as e:
            logger.error(f"Error creating QA chain: {str(e)}")
            raise
    
    def query(self, question: str) -> Dict[str, Any]:
        """Process user query and return answer with sources"""
        try:
            # Validate input
            if not question or not isinstance(question, str):
                raise ValueError("Question must be a non-empty string")
            
            # Check if chain exists
            if not self.qa_chain:
                raise RuntimeError("QA chain not initialized. Call create_qa_chain first.")
            
            # Process query
            result = self.qa_chain({"query": question})
            
            # Sanitize output
            answer = result.get("result", "")
            source_documents = result.get("source_documents", [])
            
            # Extract source information
            sources = []
            for doc in source_documents:
                sources.append({
                    "content": doc.page_content[:200] + "..." if len(doc.page_content) > 200 else doc.page_content,
                    "metadata": doc.metadata
                })
            
            return {
                "answer": answer,
                "sources": sources,
                "query": question
            }
            
        except Exception as e:
            logger.error(f"Error processing query: {str(e)}")
            raise

